INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1285, 190662, 6, 299, '一��人的承�Z', '“虫，海的另一边会是天堂吗？”
<br>“傻瓜，世上怎么会有天堂呢？海的另一边依然是我们脚踏的大地，人再强也逃不开我们所处的这个地球。天堂，只是梦想的国度罢了。”
<br>“梦想的国度。。”她静静的说完这几个字，便再度沉默了。看着她，突然心里有丝丝的不安，本来说好今天快快乐乐的来看看海的，怎么突然她会这么问这样的问题。不敢去打破这份沉默。海风吹扶着她的到肩的长发时，她的身影竟然让我有种陌生的感觉，仿佛一个从来就不认识的她在面前。“可能呢，与她在一起三年了，怎么还会有这种陌生感觉呢。”自己嘲笑自己的幼稚，甩甩头把这种念头抛开。“XX，这儿冷，回去吧。”轻轻的说着，可是她似乎没听到。眼睛一直盯着远方的海面呆呆的看着。本来已经被抛开的念头似乎又钻进了脑子，比先前更强烈，心莫名的不安起来。轻轻走到她身后，缓缓的环抱着她。“怎么了，突然发觉今天的你很不一样。有心事吗？”她静静的靠在怀中，这让我感到温馨。“没什么，只是看到海突然有所感悟。”“嗯，没事就好。啊。啊啾！！”一阵冷意让自己忍不住打了个寒颤。“你看看，叫你多穿件衣服来就是不听。被凉着了吧。”“呵呵，怕什么，我有个热呼呼的保温器呢~”说完将她抱得更紧了，“贫嘴，回去吧。”“嗯！”
<br>认识XX已经三年了，依然还记得第一次遇到她那一刻：三年前，站在寂静的月台上，再次挥手告别远去的朋友，望着远去的列车，轻轻叹了口气，回身踏上归来之路,朋友逐渐的远离，投入属于自己的生活中，最后只剩下自己孤零零一个人徘徊在校园，望着空旷的校园、寂静的宿舍，突然发觉原来自己是如此的孤独。三年来的学习生涯转眼即过，那份最初入校的心情仿佛就在昨日才存在，它是如此的清晰，清晰到让自己无法压抑心中那份伤悲。踏进满地一片狼籍的宿舍楼，仿佛走回了寂寞的怀中。 每踏上一层心中便多一份凄凉、一份空荡，抬头望见的是熟悉的墙壁，昨日还在此一起嬉戏，今日各自便像鸟儿一样飞散，一阵阵酸楚油然从心中升起。心情很乱，不想呆在这熟悉的地方，那样只会更加伤感，便打算出去走走，当路过女生宿舍时，抬头看着它。三年了，却没有一个女孩可以让自己心动，如今就要离开。没有机会了。
<br>走进车库，准备骑着单车乱逛时，突然，一声“让让。小心啊！”的尖叫声，“砰~”，一重物落地的声音，不用说，倒下的就是我。那一声尖叫我一辈子也会记住，耳膜都快叫破的声音，有时我真的佩服有人能叫出这么高的声调，可惜那些“音探”没听到，不然一定抓那女孩去唱女高音。等我清醒过来时，已经是在医护室了，“我怎么了？”醒来第一件事就是这个，“对不起，对不起。”身边一个女声响起，这时才发觉身边还有一位女孩。“你没怎么，只是晕倒了一会。”医师轻轻说道。我抬头与那女孩的目光接触到，清纯的眼神充满了谦意。想必就是她撞晕我的吧。“对不起，我不是故意的。只是下坡的时候才发觉刹车坏了。所以，所以。。。。”女孩拼命的去解释，满脸通红的样子。突然觉得她很可爱。“哦，没事，没事。还好我经常锻炼，这种小撞是撞不死我的啦。除非来架东风！”打哈哈似的跟她说，“可是，可是，你真的没事吗？一撞你都晕过去了。”唉，真是哪壶不开提哪壶。老大，拜托别再提我的糗事了，如果让那些家伙知道单车这么轻轻的“吻”上我就晕了。那不是要他们笑掉大牙吗？ “没事没事，你看。我都可以跳起来了。”我说着就从床上跳起来，“砰！”又是一声巨响，“砰！”第二声。。在晕的刹那，耳朵还有着床板叽叽的嘲笑声。因为忘记了，医务室的床是二层的，在我起跳时脑袋又与床板来了个“亲密接吻”“唉，这孩子，就这么急，我真不知道该怎么说他了。”医师摇摇头唉气说。女孩噔大眼睛说不出一句话，不知道她是强忍着还是怎么的。反正在我醒来后她脸比刚才还要红。从医务室走出来，摸摸头上的大红包，直叹倒霉。女孩一直没说话，我知道她想笑，只是强忍着。瞅了她一眼，装得冷冷的声音说了一声：“想笑就笑吧，别忍着。”“哈哈哈。”在我说完这句时，耳边又再次有种被震破的感觉。满校园都回荡着她的笑声，还好在校的人都不多，只是有几个人伸出窗口向这边望望，也许是奇怪吧。足足三分钟，笑声才渐渐变小。“喂，你笑够了吧。”不爽的看着她，“我。我。。哈哈。。等。。等。。哈哈。下。。”我靠，笑到话都说不清楚。“呼！”她深深呼吸了一口气，好容易止住了笑，“笑完了？”冷冷说道，“嗯，嘻嘻。”她看着我时，又把头撇到一边，笑出声来。“我就这么好笑啊？”“嗯，老实说，是真的好好笑，我是第一次见到有人用头去撞床板。”。。。“。。“也不知道是是谁让我这弱小的身体连受两次重创。”“咦。怎么又成弱小了？刚你不是说经常锻炼吗？”“#￥%##%%#”心里在说着这样的话。我真服了这个女孩，说话的时候一板一眼的。“再强的身体受两次重创也受不了啊。你还好意思这样说啊？”“对不起啦，这样吧。我请你吃烧料，当是补偿吧。好吗？”女孩似乎也知道错在自己。“你说的！便宜你了。走吧”。有时真的不明白，为什么就这么自然的跟一位从没谋面的女孩这么轻松的说话。那天吃完烧料后，她就说有事先走了。我也没说什么，只是说了声：“走好。”事后才后悔忘记问她的名字和联系方法了。算了，随缘吧。把该带的东西，该拿的东西都装好后，自己也踏上了离开的的路。别了，校园；别了，学生时代的恋爱。
<br>                                        ――待续', '“虫，海的另一边会是天堂吗？”

